import { describe, it, expect, vi } from "vitest";
import type { ModelMessage } from "ai";

// Import all types under test
import type {
  Message,
  CheckpointMessage,
  SessionMetadata,
  CompactionConfig,
  PruningConfig,
  ContinuationVariant,
  CompactionResult,
  PreparedCompactionV2,
  ActualTokenUsage,
  ActualTokenUsageInput,
  ContextUsage,
  TodoItem,
  StructuredState,
  SessionHeaderLine,
  MessageLine,
  CheckpointLine,
  SessionFileLine,
  CompactionSummary,
  CompactionSegment,
  PreparedCompactionSegment,
  PreparedCompaction,
} from "./compaction-types";

describe("compaction-types", () => {
  describe("Message interface", () => {
    it("should require all non-optional fields", () => {
      const message: Message = {
        createdAt: new Date(),
        id: "msg-123",
        modelMessage: { role: "user", content: "Hello" },
      };
      expect(message.createdAt).toBeInstanceOf(Date);
      expect(message.id).toBe("msg-123");
    });

    it("should allow optional originalContent field", () => {
      const messageWithOptional: Message = {
        createdAt: new Date(),
        id: "msg-123",
        modelMessage: { role: "user", content: "Hello" },
        originalContent: "original",
      };

      const messageWithoutOptional: Message = {
        createdAt: new Date(),
        id: "msg-456",
        modelMessage: { role: "assistant", content: "Hi" },
      };

      expect(messageWithOptional.originalContent).toBe("original");
      expect(messageWithoutOptional.originalContent).toBeUndefined();
    });

    it("should have correct field types", () => {
      const message: Message = {
        createdAt: new Date(2024, 0, 1),
        id: "test-id",
        modelMessage: { role: "system", content: "You are helpful" },
        originalContent: "original content",
      };

      expect(typeof message.createdAt).toBe("object");
      expect(typeof message.id).toBe("string");
      expect(typeof message.modelMessage).toBe("object");
      expect(typeof message.originalContent).toBe("string");
    });
  });

  describe("CheckpointMessage interface", () => {
    it("should require all non-optional fields", () => {
      const checkpoint: CheckpointMessage = {
        createdAt: Date.now(),
        id: "checkpoint-123",
        isSummary: true,
        message: { role: "user", content: "Test" },
      };

      expect(typeof checkpoint.createdAt).toBe("number");
      expect(checkpoint.id).toBe("checkpoint-123");
      expect(checkpoint.isSummary).toBe(true);
    });

    it("should allow optional isSummaryMessage field", () => {
      const withOptional: CheckpointMessage = {
        createdAt: Date.now(),
        id: "cp-1",
        isSummary: false,
        isSummaryMessage: true,
        message: { role: "user", content: "Test" },
      };

      const withoutOptional: CheckpointMessage = {
        createdAt: Date.now(),
        id: "cp-2",
        isSummary: false,
        message: { role: "user", content: "Test" },
      };

      expect(withOptional.isSummaryMessage).toBe(true);
      expect(withoutOptional.isSummaryMessage).toBeUndefined();
    });

    it("should have correct field types", () => {
      const checkpoint: CheckpointMessage = {
        createdAt: 1704067200000,
        id: "test-checkpoint",
        isSummary: false,
        isSummaryMessage: false,
        message: { role: "assistant", content: "Response" },
        originalContent: "original",
      };

      expect(checkpoint.createdAt).toBe(1704067200000);
      expect(checkpoint.id).toBe("test-checkpoint");
      expect(checkpoint.isSummary).toBe(false);
      expect(checkpoint.isSummaryMessage).toBe(false);
      expect(typeof checkpoint.message).toBe("object");
      expect(checkpoint.originalContent).toBe("original");
    });
  });

  describe("SessionMetadata interface", () => {
    it("should require all fields (no optional fields)", () => {
      const session: SessionMetadata = {
        completionTokens: 100,
        createdAt: Date.now(),
        promptTokens: 200,
        sessionId: "session-123",
        summaryMessageId: null,
        updatedAt: Date.now(),
      };

      expect(session.completionTokens).toBe(100);
      expect(session.promptTokens).toBe(200);
      expect(session.sessionId).toBe("session-123");
      expect(session.summaryMessageId).toBe(null);
    });

    it("should allow summaryMessageId to be string after compaction", () => {
      const sessionWithSummary: SessionMetadata = {
        completionTokens: 100,
        createdAt: Date.now(),
        promptTokens: 200,
        sessionId: "session-123",
        summaryMessageId: "summary-msg-id",
        updatedAt: Date.now(),
      };

      expect(typeof sessionWithSummary.summaryMessageId).toBe("string");
    });

    it("should have correct numeric field types", () => {
      const session: SessionMetadata = {
        completionTokens: 500,
        createdAt: 1704067200000,
        promptTokens: 1000,
        sessionId: "test-session",
        summaryMessageId: null,
        updatedAt: 1704153600000,
      };

      expect(session.completionTokens).toBe(500);
      expect(session.createdAt).toBe(1704067200000);
      expect(session.promptTokens).toBe(1000);
      expect(session.updatedAt).toBe(1704153600000);
    });
  });

  describe("CompactionConfig interface", () => {
    it("should allow empty config (all fields optional)", () => {
      const emptyConfig: CompactionConfig = {};
      expect(emptyConfig).toEqual({});
    });

    it("should accept all optional fields", () => {
      const fullConfig: CompactionConfig = {
        contextLimit: 128000,
        enabled: true,
        getStructuredState: () => "<state>test</state>",
        keepRecentTokens: 2000,
        maxTokens: 8000,
        reserveTokens: 2000,
        speculativeStartRatio: 0.5,
        summarizeFn: async (msgs) => "summary",
        thresholdRatio: 0.5,
      };

      expect(fullConfig.contextLimit).toBe(128000);
      expect(fullConfig.enabled).toBe(true);
      expect(fullConfig.keepRecentTokens).toBe(2000);
      expect(fullConfig.maxTokens).toBe(8000);
      expect(fullConfig.reserveTokens).toBe(2000);
      expect(fullConfig.speculativeStartRatio).toBe(0.5);
      expect(fullConfig.thresholdRatio).toBe(0.5);
    });

    it("should accept function for getStructuredState", () => {
      const config: CompactionConfig = {
        getStructuredState: () => "structured state",
      };

      expect(typeof config.getStructuredState).toBe("function");
      expect(config.getStructuredState!()).toBe("structured state");
    });

    it("should accept undefined return from getStructuredState", () => {
      const config: CompactionConfig = {
        getStructuredState: () => undefined,
      };

      expect(config.getStructuredState!()).toBeUndefined();
    });

    it("should accept summarizeFn function", () => {
      const summarizeFn = async (messages: ModelMessage[], previousSummary?: string) => {
        return `Summary of ${messages.length} messages`;
      };

      const config: CompactionConfig = {
        summarizeFn,
      };

      expect(typeof config.summarizeFn).toBe("function");
    });

    it("should have correct default value hints in JSDoc for contextLimit", () => {
      const config: CompactionConfig = {
        contextLimit: 0, // 0 or undefined means unlimited
      };

      expect(config.contextLimit).toBe(0);
    });

    it("should have correct default value hints for keepRecentTokens", () => {
      const config: CompactionConfig = {
        keepRecentTokens: 1000,
      };

      expect(config.keepRecentTokens).toBe(1000);
    });

    it("should accept thresholdRatio between 0 and 1", () => {
      const configMin: CompactionConfig = { thresholdRatio: 0 };
      const configMax: CompactionConfig = { thresholdRatio: 1 };
      const configMid: CompactionConfig = { thresholdRatio: 0.5 };

      expect(configMin.thresholdRatio).toBe(0);
      expect(configMax.thresholdRatio).toBe(1);
      expect(configMid.thresholdRatio).toBe(0.5);
    });

    it("should accept speculativeStartRatio between 0.15 and 0.95", () => {
      const config: CompactionConfig = {
        speculativeStartRatio: 0.75,
      };

      expect(config.speculativeStartRatio).toBe(0.75);
    });
  });

  describe("PruningConfig interface", () => {
    it("should allow empty config (all fields optional)", () => {
      const emptyConfig: PruningConfig = {};
      expect(emptyConfig).toEqual({});
    });

    it("should accept all optional fields", () => {
      const fullConfig: PruningConfig = {
        enabled: true,
        minSavingsTokens: 200,
        protectedToolNames: ["tool1", "tool2"],
        protectRecentTokens: 2000,
        replacementText: "[output pruned — too large]",
      };

      expect(fullConfig.enabled).toBe(true);
      expect(fullConfig.minSavingsTokens).toBe(200);
      expect(fullConfig.protectedToolNames).toEqual(["tool1", "tool2"]);
      expect(fullConfig.protectRecentTokens).toBe(2000);
      expect(fullConfig.replacementText).toBe("[output pruned — too large]");
    });

    it("should have correct default value hints", () => {
      const config: PruningConfig = {
        minSavingsTokens: 100,
        protectRecentTokens: 1500,
        replacementText: "[pruned]",
      };

      expect(config.minSavingsTokens).toBe(100);
      expect(config.protectRecentTokens).toBe(1500);
      expect(config.replacementText).toBe("[pruned]");
    });
  });

  describe("ContinuationVariant type", () => {
    it("should accept 'manual' variant", () => {
      const variant: ContinuationVariant = "manual";
      expect(variant).toBe("manual");
    });

    it("should accept 'auto-with-replay' variant", () => {
      const variant: ContinuationVariant = "auto-with-replay";
      expect(variant).toBe("auto-with-replay");
    });

    it("should accept 'tool-loop' variant", () => {
      const variant: ContinuationVariant = "tool-loop";
      expect(variant).toBe("tool-loop");
    });

    it("should be a union type of string literals", () => {
      const variants: ContinuationVariant[] = [
        "manual",
        "auto-with-replay",
        "tool-loop",
      ];

      expect(variants).toHaveLength(3);
    });
  });

  describe("CompactionResult interface", () => {
    it("should require success field", () => {
      const result: CompactionResult = {
        success: true,
        tokensBefore: 1000,
        tokensAfter: 500,
      };

      expect(result.success).toBe(true);
      expect(result.tokensBefore).toBe(1000);
      expect(result.tokensAfter).toBe(500);
    });

    it("should allow optional fields", () => {
      const fullResult: CompactionResult = {
        continuationVariant: "manual",
        reason: "Token limit exceeded",
        success: false,
        summaryMessageId: "summary-123",
        tokensBefore: 1000,
        tokensAfter: 800,
      };

      const minimalResult: CompactionResult = {
        success: true,
        tokensBefore: 500,
        tokensAfter: 300,
      };

      expect(fullResult.continuationVariant).toBe("manual");
      expect(fullResult.reason).toBe("Token limit exceeded");
      expect(fullResult.summaryMessageId).toBe("summary-123");

      expect(minimalResult.continuationVariant).toBeUndefined();
      expect(minimalResult.reason).toBeUndefined();
      expect(minimalResult.summaryMessageId).toBeUndefined();
    });

    it("should have correct token field types", () => {
      const result: CompactionResult = {
        success: true,
        tokensBefore: 5000,
        tokensAfter: 3000,
      };

      expect(typeof result.tokensBefore).toBe("number");
      expect(typeof result.tokensAfter).toBe("number");
    });

    it("should support different continuation variants", () => {
      const manualResult: CompactionResult = {
        success: true,
        tokensBefore: 1000,
        tokensAfter: 500,
        continuationVariant: "manual",
      };

      const autoResult: CompactionResult = {
        success: true,
        tokensBefore: 1000,
        tokensAfter: 500,
        continuationVariant: "auto-with-replay",
      };

      const toolLoopResult: CompactionResult = {
        success: true,
        tokensBefore: 1000,
        tokensAfter: 500,
        continuationVariant: "tool-loop",
      };

      expect(manualResult.continuationVariant).toBe("manual");
      expect(autoResult.continuationVariant).toBe("auto-with-replay");
      expect(toolLoopResult.continuationVariant).toBe("tool-loop");
    });
  });

  describe("PreparedCompactionV2 interface", () => {
    it("should require all non-optional fields", () => {
      const compaction: PreparedCompactionV2 = {
        baseMessageIds: ["msg-1", "msg-2"],
        revision: 1,
        splitIndex: 5,
        summaryText: "This is a summary",
        tokenDelta: -500,
