{"path": "packages/harness/src/compaction-types.test.ts", "content": "import { describe, it, expect } from "vitest";
import type { ModelMessage } from "ai";
import type {
  Message,
  CheckpointMessage,
  SessionMetadata,
  CompactionConfig,
  PruningConfig,
  ContinuationVariant,
  CompactionResult,
  PreparedCompactionV2,
  ActualTokenUsage,
  ActualTokenUsageInput,
  ContextUsage,
  TodoItem,
  StructuredState,
  SessionHeaderLine,
  MessageLine,
  CheckpointLine,
  SessionFileLine,
  CompactionSummary,
  CompactionSegment,
  PreparedCompactionSegment,
  PreparedCompaction,
} from "./compaction-types";

// ============================================================================
// Test Utils
// ============================================================================

/**
 * Helper to check if a type is exactly another type
 */
type ExpectType<T> = T;

/**
 * Helper to check if two types are assignable
 */
type ExpectAssignable<T, U extends T> = U;

// ============================================================================
// 1. Message Interface Tests
// ============================================================================

describe("Message", () => {
  // Required fields
  it("should accept message with all required fields", () => {
    const message: Message = {
      createdAt: new Date(),
      id: "msg-123",
      modelMessage: { role: "user", content: "Hello" },
    };
    expect(message.createdAt).toBeInstanceOf(Date);
    expect(message.id).toBe("msg-123");
    expect(message.modelMessage).toBeDefined();
  });

  // Optional fields - presence
  it("should accept message with optional originalContent", () => {
    const message: Message = {
      createdAt: new Date(),
      id: "msg-123",
      modelMessage: { role: "user", content: "Hello" },
      originalContent: "Original text",
    };
    expect(message.originalContent).toBe("Original text");
  });

  // Optional fields - absence
  it("should accept message without optional originalContent", () => {
    const message: Message = {
      createdAt: new Date(),
      id: "msg-123",
      modelMessage: { role: "user", content: "Hello" },
    };
    expect(message.originalContent).toBeUndefined();
  });

  // Type compatibility - originalContent should be string | undefined
  it("should have correct type for optional originalContent", () => {
    const message: Message = {
      createdAt: new Date(),
      id: "msg-123",
      modelMessage: { role: "user", content: "Hello" },
    };

    // Should be assignable to string | undefined
    const maybeString: string | undefined = message.originalContent;
    expect(maybeString).toBeUndefined();
  });

  // Type compatibility - can accept ModelMessage directly
  it("should accept ModelMessage with different content types", () => {
    const textMessage: Message = {
      createdAt: new Date(),
      id: "msg-1",
      modelMessage: { role: "user", content: "Text only" },
    };

    const partsMessage: Message = {
      createdAt: new Date(),
      id: "msg-2",
      modelMessage: { role: "assistant", content: [{ type: "text", text: "Hello" }] },
    };

    expect(textMessage.modelMessage.content).toBe("Text only");
    expect(partsMessage.modelMessage.content).toHaveLength(1);
  });
});

// ============================================================================
// 2. CheckpointMessage Interface Tests
// ============================================================================

describe("CheckpointMessage", () => {
  // Required fields
  it("should accept checkpoint message with all required fields", () => {
    const checkpoint: CheckpointMessage = {
      createdAt: Date.now(),
      id: "cp-123",
      isSummary: false,
      message: { role: "user", content: "Test" },
    };
    expect(checkpoint.createdAt).toBeDefined();
    expect(checkpoint.id).toBe("cp-123");
    expect(checkpoint.isSummary).toBe(false);
    expect(checkpoint.message).toBeDefined();
  });

  // Optional fields - presence
  it("should accept checkpoint message with optional isSummaryMessage", () => {
    const checkpoint: CheckpointMessage = {
      createdAt: Date.now(),
      id: "cp-123",
      isSummary: true,
      message: { role: "user", content: "Test" },
      isSummaryMessage: true,
    };
    expect(checkpoint.isSummaryMessage).toBe(true);
  });

  it("should accept checkpoint message with optional originalContent", () => {
    const checkpoint: CheckpointMessage = {
      createdAt: Date.now(),
      id: "cp-123",
      isSummary: false,
      message: { role: "user", content: "Test" },
      originalContent: "Original text",
    };
    expect(checkpoint.originalContent).toBe("Original text");
  });

  // Optional fields - absence
  it("should accept checkpoint message without optional isSummaryMessage", () => {
    const checkpoint: CheckpointMessage = {
      createdAt: Date.now(),
      id: "cp-123",
      isSummary: false,
      message: { role: "user", content: "Test" },
    };
    expect(checkpoint.isSummaryMessage).toBeUndefined();
  });

  it("should accept checkpoint message without optional originalContent", () => {
    const checkpoint: CheckpointMessage = {
      createdAt: Date.now(),
      id: "cp-123",
      isSummary: false,
      message: { role: "user", content: "Test" },
    };
    expect(checkpoint.originalContent).toBeUndefined();
  });

  // Type compatibility - createdAt should be number (Date.now())
  it("should have createdAt as number", () => {
    const checkpoint: CheckpointMessage = {
      createdAt: 1234567890,
      id: "cp-123",
      isSummary: false,
      message: { role: "user", content: "Test" },
    };
    expect(typeof checkpoint.createdAt).toBe("number");
  });

  // Type compatibility - isSummary is boolean
  it("should have isSummary as boolean", () => {
    const checkpointTrue: CheckpointMessage = {
      createdAt: Date.now(),
      id: "cp-1",
      isSummary: true,
      message: { role: "user", content: "Test" },
    };
    const checkpointFalse: CheckpointMessage = {
      createdAt: Date.now(),
      id: "cp-2",
      isSummary: false,
      message: { role: "user", content: "Test" },
    };
    expect(typeof checkpointTrue.isSummary).toBe("boolean");
    expect(typeof checkpointFalse.isSummary).toBe("boolean");
  });
});

// ============================================================================
// 3. SessionMetadata Interface Tests
// ============================================================================

describe("SessionMetadata", () => {
  // All required fields
  it("should accept session metadata with all required fields", () => {
    const metadata: SessionMetadata = {
      completionTokens: 100,
      createdAt: Date.now(),
      promptTokens: 50,
      sessionId: "session-123",
      summaryMessageId: null,
      updatedAt: Date.now(),
    };
    expect(metadata.completionTokens).toBe(100);
    expect(metadata.promptTokens).toBe(50);
    expect(metadata.sessionId).toBe("session-123");
    expect(metadata.summaryMessageId).toBeNull();
    expect(metadata.createdAt).toBeDefined();
    expect(metadata.updatedAt).toBeDefined();
  });

  // summaryMessageId can be string
  it("should accept summaryMessageId as string when compaction happened", () => {
    const metadata: SessionMetadata = {
      completionTokens: 100,
      createdAt: Date.now(),
      promptTokens: 50,
      sessionId: "session-123",
      summaryMessageId: "summary-msg-456",
      updatedAt: Date.now(),
    };
    expect(typeof metadata.summaryMessageId).toBe("string");
  });

  // summaryMessageId can be null
  it("should accept summaryMessageId as null when no compaction yet", () => {
    const metadata: SessionMetadata = {
      completionTokens: 100,
      createdAt: Date.now(),
      promptTokens: 50,
      sessionId: "session-123",
      summaryMessageId: null,
      updatedAt: Date.now(),
    };
    expect(metadata.summaryMessageId).toBeNull();
  });

  // Type compatibility - token counts should be numbers
  it("should have numeric token fields", () => {
    const metadata: SessionMetadata = {
      completionTokens: 0,
      createdAt: Date.now(),
      promptTokens: 0,
      sessionId: "session-123",
      summaryMessageId: null,
      updatedAt: Date.now(),
    };
    expect(typeof metadata.completionTokens).toBe("number");
    expect(typeof metadata.promptTokens).toBe("number");
  });

  // Type compatibility - timestamp fields should be numbers
  it("should have numeric timestamp fields", () => {
    const metadata: SessionMetadata = {
      completionTokens: 0,
      createdAt: 1234567890,
      promptTokens: 0,
      sessionId: "session-123",
      summaryMessageId: null,
      updatedAt: 1234567899,
    };
    expect(typeof metadata.createdAt).toBe("number");
    expect(typeof metadata.updatedAt).toBe("number");
  });
});

// ============================================================================
// 4. CompactionConfig Interface Tests
// ============================================================================

describe("CompactionConfig", () => {
  // Empty config - all optional
  it("should accept empty config with no fields", () => {
