  });

  // source can be "estimated"
  it("should accept source as 'estimated'", () => {
    const usage: ContextUsage = {
      limit: 128000,
      percentage: 50,
      remaining: 64000,
      source: "estimated",
      used: 64000,
    };
    expect(usage.source).toBe("estimated");
  });

  // percentage boundaries
  it("should accept percentage at 0", () => {
    const usage: ContextUsage = {
      limit: 128000,
      percentage: 0,
      remaining: 128000,
      source: "actual",
      used: 0,
    };
    expect(usage.percentage).toBe(0);
  });

  it("should accept percentage at 100", () => {
    const usage: ContextUsage = {
      limit: 128000,
      percentage: 100,
      remaining: 0,
      source: "actual",
      used: 128000,
    };
    expect(usage.percentage).toBe(100);
  });

  // Type compatibility - source is literal union
  it("should only accept 'actual' or 'estimated'", () => {
    const usage: ContextUsage = {
      limit: 128000,
      percentage: 50,
      remaining: 64000,
      source: "actual",
      used: 64000,
    };
    expect(usage.source === "actual" || usage.source === "estimated").toBe(true);
  });

  // Type compatibility - remaining = limit - used
  it("should have consistent remaining value", () => {
    const usage: ContextUsage = {
      limit: 128000,
      percentage: 50,
      remaining: 64000,
      source: "actual",
      used: 64000,
    };
    expect(usage.remaining).toBe(usage.limit - usage.used);
  });
});

