  it("should work in array of union type", () => {
    const lines: SessionFileLine[] = [];
    lines.push({ createdAt: 1, sessionId: "s", type: "header", version: 1 });
    lines.push({ createdAt: 2, id: "m", isSummary: false, message: { role: "user", content: "c" }, type: "message" });
