describe("SessionFileLine", () => {
  // Union type - can be SessionHeaderLine
  it("should accept SessionHeaderLine", () => {
    const line: SessionFileLine = {
      createdAt: Date.now(),
      sessionId: "session-123",
      type: "header",
      version: 1,
    };
    expect(line.type).toBe("header");
  });

  // Union type - can be MessageLine
  it("should accept MessageLine", () => {
    const line: SessionFileLine = {
      createdAt: Date.now(),
      id: "msg-123",
      isSummary: false,
      message: { role: "user", content: "Hello" },
      type: "message",
    };
    expect(line.type).toBe("message");
  });

  // Union type - can be CheckpointLine
  it("should accept CheckpointLine", () => {
    const line: SessionFileLine = {
      summaryMessageId: "summary-123",
      type: "checkpoint",
      updatedAt: Date.now(),
    };
    expect(line.type).toBe("checkpoint");
  });

  // Type narrowing
  it("should allow type narrowing by type field", () => {
    const lines: SessionFileLine[] = [
      { createdAt: 1, sessionId: "s", type: "header", version: 1 },
      { createdAt: 2, id: "m", isSummary: false, message: { role: "user", content: "c" }, type: "message" },
      { summaryMessageId: "s", type: "checkpoint", updatedAt: 3 },
    ];

    for (const line of lines) {
      if (line.type === "header") {
        expect(line.version).toBe(1);
        expect(line.sessionId).toBeDefined();
      } else if (line.type === "message") {
        expect(line.id).toBeDefined();
        expect(line.message).toBeDefined();
      } else if (line.type === "checkpoint") {
        expect(line.summaryMessageId).toBeDefined();
      }
    }
  });

  // Type compatibility - can be used in arrays
  it("should work in array of union type", () => {
    const lines: SessionFileLine[] = [];
    lines.push({ createdAt: 1, sessionId: "s", type: "header", version: 1 });
    lines.push({ createdAt: 2, id: "m", isSummary: false, message: { role: "user", content: "c" }, type: "message" });
    lines.push({ summaryMessageId: "s", type: "checkpoint", updatedAt: 3 });
    expect(lines).toHaveLength(3);
  });
});

